function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
}

function treeValue(tree, features) {
    let node = tree;
    while (Array.isArray(node)) {
        node = features[node[0]] <= node[1] ? node[2] : node[3];
    }
    return Number(node) || 0;
}

export function evaluateRoxyMetaModel(features) {
    if (!Array.isArray(features) || features.length !== ROXY_META_FEATURE_NAMES.length) {
        return Number.NaN;
    }
    let value = ROXY_META_BASE;
    for (const tree of ROXY_META_TREES) {
        value += ROXY_META_LEARNING_RATE * treeValue(tree, features);
    }
    return clamp(value, -2, 20);
}
